    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // fetchTickers
        //
        //      [
        //         1639472400, // timestamp
        //         4.26, // low
        //         4.38, // high
        //         4.35, // open
        //         4.27 // close
        //      ]
        //
        // fetchTicker
        //
        //     publicGetProductsIdTicker
        //
        //     {
        //         "trade_id":843439,
        //         "price":"0.997999",
        //         "size":"80.29769",
        //         "time":"2020-01-28T02:13:33.012523Z",
        //         "bid":"0.997094",
        //         "ask":"0.998",
        //         "volume":"1903188.03750000"
        //     }
        //
        //     publicGetProductsIdStats
        //
        //     {
        //         "open": "34.19000000",
        //         "high": "95.70000000",
        //         "low": "7.06000000",
        //         "volume": "2.41000000"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = null;
        Object bid = null;
        Object ask = null;
        Object last = null;
        Object high = null;
        Object low = null;
        Object open = null;
        Object volume = null;
        Object symbol = ((Helpers.isTrue((Helpers.isEqual(market, null))))) ? null : Helpers.GetValue(market, "symbol");
        if (Helpers.isTrue(Helpers.isArray(ticker)))
        {
            last = this.safeString(ticker, 4);
            timestamp = this.milliseconds();
        } else
        {
            timestamp = this.parse8601(this.safeValue(ticker, "time"));
            bid = this.safeString(ticker, "bid");
            ask = this.safeString(ticker, "ask");
            high = this.safeString(ticker, "high");
            low = this.safeString(ticker, "low");
            open = this.safeString(ticker, "open");
            last = this.safeString2(ticker, "price", "last");
            volume = this.safeString(ticker, "volume");
        }
        final Object finalTimestamp = timestamp;
        final Object finalHigh = high;
        final Object finalLow = low;
        final Object finalBid = bid;
        final Object finalAsk = ask;
        final Object finalOpen = open;
        final Object finalLast = last;
        final Object finalVolume = volume;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", finalTimestamp );
            put( "datetime", CoinbaseexchangeCore.this.iso8601(finalTimestamp) );
            put( "high", finalHigh );
            put( "low", finalLow );
            put( "bid", finalBid );
            put( "bidVolume", null );
            put( "ask", finalAsk );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", finalOpen );
            put( "close", finalLast );
            put( "last", finalLast );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", null );
            put( "baseVolume", finalVolume );
            put( "quoteVolume", null );
            put( "info", ticker );
        }}, market);
    }

    /**
     * @method
     * @name coinbaseexchange#fetchTickers
     * @description fetches price tickers for multiple markets, statistical information calculated over the past 24 hours for each market
     * @see https://docs.cloud.coinbase.com/exchange/reference/exchangerestapi_getproduct
     * @param {string[]|undefined} symbols unified symbols of the markets to fetch the ticker for, all market tickers are returned if not assigned
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of [ticker structures]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTickers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            symbols = this.marketSymbols(symbols);
            Object request = new java.util.HashMap<String, Object>() {{}};
            Object response = (this.publicGetProductsSparkLines(this.extend(request, parameters))).join();
            //
            //     {
            //         YYY-USD: [
            //             [
            //                 1639472400, // timestamp
            //                 4.26, // low
            //                 4.38, // high
            //                 4.35, // open
            //                 4.27 // close
            //             ],
            //             [
            //                 1639468800,
            //                 4.31,
            //                 4.45,
            //                 4.35,
            //                 4.35
            //             ],
            //         ]
            //     }
            //
            Object result = new java.util.HashMap<String, Object>() {{}};
            Object marketIds = Helpers.objectKeys(response);
            Object delimiter = "-";
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketIds)); i++)
            {
                Object marketId = Helpers.GetValue(marketIds, i);
                Object entry = this.safeValue(response, marketId, new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                Object first = this.safeValue(entry, 0, new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                Object market = this.safeMarket(marketId, null, delimiter);
                Object symbol = Helpers.GetValue(market, "symbol");
                Helpers.addElementToObject(result, symbol, this.parseTicker(first, market));
            }
            return this.filterByArrayTickers(result, "symbol", symbols);
        });

    }

