    /**
     * @method
     * @name coinbaseexchange#createOrder
     * @see https://docs.cloud.coinbase.com/exchange/reference/exchangerestapi_postorders
     * @description create a trade order
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type2, Object side, Object amount2, Object... optionalArgs)
    {
        final Object type3 = type2;
        final Object amount3 = amount2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object amount = amount3;
            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            final Object finalType = type;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "type", finalType );
                put( "side", side );
                put( "product_id", Helpers.GetValue(market, "id") );
            }};
            Object clientOrderId = this.safeString2(parameters, "clientOrderId", "client_oid");
            if (Helpers.isTrue(!Helpers.isEqual(clientOrderId, null)))
            {
                Helpers.addElementToObject(request, "client_oid", clientOrderId);
            }
            Object triggerPrice = this.safeNumberN(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("stopPrice", "stop_price", "triggerPrice")));
            if (Helpers.isTrue(!Helpers.isEqual(triggerPrice, null)))
            {
                Helpers.addElementToObject(request, "stop_price", this.priceToPrecision(symbol, triggerPrice));
            }
            Object timeInForce = this.safeString2(parameters, "timeInForce", "time_in_force");
            if (Helpers.isTrue(!Helpers.isEqual(timeInForce, null)))
            {
                Helpers.addElementToObject(request, "time_in_force", timeInForce);
            }
            Object postOnly = this.safeValue2(parameters, "postOnly", "post_only", false);
            if (Helpers.isTrue(postOnly))
            {
                Helpers.addElementToObject(request, "post_only", true);
            }
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("timeInForce", "time_in_force", "stopPrice", "stop_price", "clientOrderId", "client_oid", "postOnly", "post_only", "triggerPrice")));
            if (Helpers.isTrue(Helpers.isEqual(type, "limit")))
            {
                Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
                Helpers.addElementToObject(request, "size", this.amountToPrecision(symbol, amount));
            } else if (Helpers.isTrue(Helpers.isEqual(type, "market")))
            {
                Object cost = this.safeNumber2(parameters, "cost", "funds");
                if (Helpers.isTrue(Helpers.isEqual(cost, null)))
                {
                    if (Helpers.isTrue(!Helpers.isEqual(price, null)))
                    {
                        cost = Helpers.multiply(amount, price);
                    }
                } else
                {
                    parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("cost", "funds")));
                }
                if (Helpers.isTrue(!Helpers.isEqual(cost, null)))
                {
                    Helpers.addElementToObject(request, "funds", this.costToPrecision(symbol, cost));
                } else
                {
                    Helpers.addElementToObject(request, "size", this.amountToPrecision(symbol, amount));
                }
            }
            Object response = (this.privatePostOrders(this.extend(request, parameters))).join();
            //
            //     {
            //         "id": "d0c5340b-6d6c-49d9-b567-48c4bfca13d2",
            //         "price": "0.10000000",
            //         "size": "0.01000000",
            //         "product_id": "BTC-USD",
            //         "side": "buy",
            //         "stp": "dc",
            //         "type": "limit",
            //         "time_in_force": "GTC",
            //         "post_only": false,
            //         "created_at": "2016-12-08T20:02:28.53864Z",
            //         "fill_fees": "0.0000000000000000",
            //         "filled_size": "0.00000000",
            //         "executed_value": "0.0000000000000000",
            //         "status": "pending",
            //         "settled": false
            //     }
            //
            return this.parseOrder(response, market);
        });

    }

