    /**
     * @method
     * @name coinbaseexchange#withdraw
     * @description make a withdrawal
     * @see https://docs.cloud.coinbase.com/exchange/reference/exchangerestapi_postwithdrawpaymentmethod
     * @see https://docs.cloud.coinbase.com/exchange/reference/exchangerestapi_postwithdrawcoinbaseaccount
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code, Object amount, Object address, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            var tagparametersVariable = this.handleWithdrawTagAndParams(tag, parameters);
            tag = ((java.util.List<Object>) tagparametersVariable).get(0);
            parameters = ((java.util.List<Object>) tagparametersVariable).get(1);
            this.checkAddress(address);
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "currency", Helpers.GetValue(currency, "id") );
                put( "amount", amount );
            }};
            Object method = "privatePostWithdrawals";
            if (Helpers.isTrue(Helpers.inOp(parameters, "payment_method_id")))
            {
                method = Helpers.add(method, "PaymentMethod");
            } else if (Helpers.isTrue(Helpers.inOp(parameters, "coinbase_account_id")))
            {
                method = Helpers.add(method, "CoinbaseAccount");
            } else
            {
                method = Helpers.add(method, "Crypto");
                Helpers.addElementToObject(request, "crypto_address", address);
                if (Helpers.isTrue(!Helpers.isEqual(tag, null)))
                {
                    Helpers.addElementToObject(request, "destination_tag", tag);
                }
            }
            Object response = ((java.util.concurrent.CompletableFuture<Object>)Helpers.callDynamically(this, method, new Object[] { this.extend(request, parameters) })).join();
            if (!Helpers.isTrue(response))
            {
                throw new ExchangeError((String)Helpers.add(Helpers.add(this.id, " withdraw() error: "), this.json(response))) ;
            }
            return this.parseTransaction(response, currency);
        });

    }

    public Object parseLedgerEntryType(Object type)
    {
        Object types = new java.util.HashMap<String, Object>() {{
            put( "transfer", "transfer" );
            put( "match", "trade" );
            put( "fee", "fee" );
            put( "rebate", "rebate" );
            put( "conversion", "trade" );
        }};
        return this.safeString(types, type, type);
    }

    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        //  {
        //      "id": "12087495079",
        //      "amount": "-0.0100000000000000",
        //      "balance": "0.0645419900000000",
        //      "created_at": "2021-10-28T17:14:32.593168Z",
        //      "type": "transfer",
        //      "details": {
        //          "from": "2f74edf7-1440-4586-86dc-ae58c5693691",
        //          "profile_transfer_id": "3ef093ad-2482-40d1-8ede-2f89cff5099e",
        //          "to": "dda99503-4980-4b60-9549-0b770ee51336"
        //      }
        //  },
        //  {
        //     "id": "11740725774",
        //     "amount": "-1.7565669701255000",
        //     "balance": "0.0016490047745000",
        //     "created_at": "2021-10-22T03:47:34.764122Z",
        //     "type": "fee",
        //     "details": {
        //         "order_id": "ad06abf4-95ab-432a-a1d8-059ef572e296",
        //         "product_id": "ETH-DAI",
        //         "trade_id": "1740617"
        //     }
        //  }
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(item, "id");
        Object amountString = this.safeString(item, "amount");
        Object direction = null;
        Object afterString = this.safeString(item, "balance");
        Object beforeString = Precise.stringSub(afterString, amountString);
        if (Helpers.isTrue(Precise.stringLt(amountString, "0")))
        {
            direction = "out";
            amountString = Precise.stringAbs(amountString);
        } else
        {
            direction = "in";
        }
        Object amount = this.parseNumber(amountString);
        Object after = this.parseNumber(afterString);
        Object before = this.parseNumber(beforeString);
        Object timestamp = this.parse8601(this.safeValue(item, "created_at"));
        Object type = this.parseLedgerEntryType(this.safeString(item, "type"));
        Object code = this.safeCurrencyCode(null, currency);
        Object details = this.safeValue(item, "details", new java.util.HashMap<String, Object>() {{}});
        Object account = null;
        Object referenceAccount = null;
        Object referenceId = null;
        if (Helpers.isTrue(Helpers.isEqual(type, "transfer")))
        {
            account = this.safeString(details, "from");
            referenceAccount = this.safeString(details, "to");
            referenceId = this.safeString(details, "profile_transfer_id");
        } else
        {
            referenceId = this.safeString(details, "order_id");
        }
        Object status = "ok";
        final Object finalDirection = direction;
        final Object finalAccount = account;
        final Object finalReferenceAccount = referenceAccount;
        final Object finalReferenceId = referenceId;
        final Object finalType = type;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "info", item );
            put( "id", id );
            put( "timestamp", timestamp );
            put( "datetime", CoinbaseexchangeCore.this.iso8601(timestamp) );
            put( "direction", finalDirection );
            put( "account", finalAccount );
            put( "referenceAccount", finalReferenceAccount );
            put( "referenceId", finalReferenceId );
            put( "type", finalType );
            put( "currency", code );
            put( "amount", amount );
            put( "before", before );
            put( "after", after );
            put( "status", status );
            put( "fee", null );
        }}, currency);
    }

    /**
     * @method
     * @name coinbaseexchange#fetchLedger
     * @description fetch the history of changes, actions done by the user or operations that altered the balance of the user
     * @see https://docs.cloud.coinbase.com/exchange/reference/exchangerestapi_getaccountledger
     * @param {string} code unified currency code, default is undefined
     * @param {int} [since] timestamp in ms of the earliest ledger entry, default is undefined
     * @param {int} [limit] max number of ledger entries to return, default is undefined
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] the latest time in ms to fetch trades for
     * @returns {object} a [ledger structure]{@link https://docs.ccxt.com/?id=ledger-entry-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchLedger(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // https://docs.cloud.coinbase.com/exchange/reference/exchangerestapi_getaccountledger
            Object code = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(code, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchLedger() requires a code param")) ;
            }
            (this.loadMarkets()).join();
            (this.loadAccounts()).join();
            Object currency = this.currency(code);
            Object accountsByCurrencyCode = this.indexBy(this.accounts, "code");
            Object account = this.safeValue(accountsByCurrencyCode, code);
            if (Helpers.isTrue(Helpers.isEqual(account, null)))
            {
                throw new ExchangeError((String)Helpers.add(Helpers.add(this.id, " fetchLedger() could not find account id for "), code)) ;
            }
            final Object finalAccount = account;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "id", Helpers.GetValue(finalAccount, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "start_date", this.iso8601(since));
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit); // default 100
            }
            Object until = this.safeValue2(parameters, "until", "end_date");
            if (Helpers.isTrue(!Helpers.isEqual(until, null)))
            {
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("until")));
                Helpers.addElementToObject(request, "end_date", this.iso8601(until));
            }
            Object response = (this.privateGetAccountsIdLedger(this.extend(request, parameters))).join();
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(response)); i++)
            {
                Helpers.addElementToObject(Helpers.GetValue(response, i), "currency", code);
            }
            return this.parseLedger(response, currency, since, limit);
        });

    }

