    public Object parseTransactionStatus(Object transaction)
    {
        Object canceled = this.safeValue(transaction, "canceled_at");
        if (Helpers.isTrue(canceled))
        {
            return "canceled";
        }
        Object processed = this.safeValue(transaction, "processed_at");
        Object completed = this.safeValue(transaction, "completed_at");
        if (Helpers.isTrue(completed))
        {
            return "ok";
        } else if (Helpers.isTrue(Helpers.isTrue(processed) && !Helpers.isTrue(completed)))
        {
            return "failed";
        } else
        {
            return "pending";
        }
    }

    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // privateGetTransfers
        //
        //    [
        //        {
        //            "id": "bee6fd7c-afb2-4e47-8298-671d09997d16",
        //            "type": "deposit",
        //            "created_at": "2022-12-21 00:48:45.477503+00",
        //            "completed_at": null,
        //            "account_id": "sal3802-36bd-46be-a7b8-alsjf383sldak",     // only from privateGetTransfers
        //            "user_id": "6382048209f92as392039dlks2",                  // only from privateGetTransfers
        //            "amount": "0.01000000",
        //            "details": {
        //                "network": "litecoin",
        //                "crypto_address": "MKemtnCFUYKsNWaf5EMYMpwSszcXWFDtTY",
        //                "coinbase_account_id": "fl2b6925-f6ba-403n-jj03-40fl435n430f",
        //                "coinbase_transaction_id": "63a25bb13cb5cf0001d2cf17", // withdrawals only
        //                "crypto_transaction_hash": "752f35570736341e2a253f7041a34cf1e196fc56128c900fd03d99da899d94c1",
        //                "tx_service_transaction_id": "1873249104",
        //                "coinbase_payment_method_id": ""
        //            },
        //            "canceled_at": null,
        //            "processed_at": null,
        //            "user_nonce": null,
        //            "idem": "5e3201b0-e390-5k3k-a913-c32932049242",
        //            "profile_id": "k3k302a8-c4dk-4f49-9d39-3203923wpk39",
        //            "currency": "LTC"
        //        }
        //    ]
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object details = this.safeValue(transaction, "details", new java.util.HashMap<String, Object>() {{}});
        Object timestamp = this.parse8601(this.safeString(transaction, "created_at"));
        Object currencyId = this.safeString(transaction, "currency");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object amount = this.safeNumber(transaction, "amount");
        Object type = this.safeString(transaction, "type");
        Object address = this.safeString(details, "crypto_address");
        address = this.safeString(transaction, "crypto_address", address);
        Object fee = new java.util.HashMap<String, Object>() {{
            put( "currency", null );
            put( "cost", null );
            put( "rate", null );
        }};
        if (Helpers.isTrue(Helpers.isEqual(type, "withdraw")))
        {
            type = "withdrawal";
            address = this.safeString(details, "sent_to_address", address);
            Object feeCost = this.safeNumber(details, "fee");
            if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
            {
                if (Helpers.isTrue(!Helpers.isEqual(amount, null)))
                {
                    amount = Helpers.subtract(amount, feeCost);
                }
                Helpers.addElementToObject(fee, "cost", feeCost);
                Helpers.addElementToObject(fee, "currency", code);
            }
        }
        Object networkId = this.safeString(details, "network");
        final Object finalType = type;
        final Object finalAmount = amount;
        final Object finalAddress = address;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", CoinbaseexchangeCore.this.safeString(transaction, "id") );
            put( "txid", CoinbaseexchangeCore.this.safeString(details, "crypto_transaction_hash") );
            put( "type", finalType );
            put( "currency", code );
            put( "network", CoinbaseexchangeCore.this.networkIdToCode(networkId, code) );
            put( "amount", finalAmount );
            put( "status", CoinbaseexchangeCore.this.parseTransactionStatus(transaction) );
            put( "timestamp", timestamp );
            put( "datetime", CoinbaseexchangeCore.this.iso8601(timestamp) );
            put( "address", finalAddress );
            put( "addressFrom", null );
            put( "addressTo", CoinbaseexchangeCore.this.safeString(details, "crypto_address") );
            put( "tag", CoinbaseexchangeCore.this.safeString(details, "destination_tag") );
            put( "tagFrom", null );
            put( "tagTo", null );
            put( "updated", CoinbaseexchangeCore.this.parse8601(CoinbaseexchangeCore.this.safeString(transaction, "processed_at")) );
            put( "comment", null );
            put( "internal", false );
            put( "fee", fee );
        }};
    }

    /**
     * @method
     * @name coinbaseexchange#createDepositAddress
     * @description create a currency deposit address
     * @see https://docs.cloud.coinbase.com/exchange/reference/exchangerestapi_postcoinbaseaccountaddresses
     * @param {string} code unified currency code of the currency for the deposit address
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [address structure]{@link https://docs.ccxt.com/?id=address-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createDepositAddress(Object code, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object accounts = this.safeValue(this.options, "coinbaseAccounts");
            if (Helpers.isTrue(Helpers.isEqual(accounts, null)))
            {
                accounts = (this.privateGetCoinbaseAccounts()).join();
                Helpers.addElementToObject(this.options, "coinbaseAccounts", accounts); // cache it
                Helpers.addElementToObject(this.options, "coinbaseAccountsByCurrencyId", this.indexBy(accounts, "currency"));
            }
            Object currencyId = Helpers.GetValue(currency, "id");
            Object account = this.safeValue(Helpers.GetValue(this.options, "coinbaseAccountsByCurrencyId"), currencyId);
            if (Helpers.isTrue(Helpers.isEqual(account, null)))
            {
                throw new InvalidAddress((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " createDepositAddress() could not find currency code "), code), " with id = "), currencyId), " in this.options['coinbaseAccountsByCurrencyId']")) ;
            }
            final Object finalAccount = account;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "id", Helpers.GetValue(finalAccount, "id") );
            }};
            Object response = (this.privatePostCoinbaseAccountsIdAddresses(this.extend(request, parameters))).join();
            Object address = this.safeString(response, "address");
            Object tag = this.safeString(response, "destination_tag");
            return new java.util.HashMap<String, Object>() {{
                put( "currency", code );
                put( "address", CoinbaseexchangeCore.this.checkAddress(address) );
                put( "network", null );
                put( "tag", tag );
                put( "info", response );
            }};
        });

    }

    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "public");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object request = Helpers.add("/", this.implodeParams(path, parameters));
        Object query = this.omit(parameters, this.extractParams(path));
        if (Helpers.isTrue(Helpers.isEqual(method, "GET")))
        {
            if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query))))
            {
                request = Helpers.add(request, Helpers.add("?", this.urlencode(query)));
            }
        }
        Object url = Helpers.add(this.implodeHostname(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), api)), request);
        if (Helpers.isTrue(Helpers.isEqual(api, "private")))
        {
            this.checkRequiredCredentials();
            Object nonce = String.valueOf(this.nonce());
            Object payload = "";
            if (Helpers.isTrue(!Helpers.isEqual(method, "GET")))
            {
                if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query))))
                {
                    body = this.json(query);
                    payload = body;
                }
            }
            Object what = Helpers.add(Helpers.add(Helpers.add(nonce, method), request), payload);
            Object secret = null;
            try
            {
                secret = this.base64ToBinary(this.secret);
            } catch(Exception e)
            {
                throw new AuthenticationError((String)Helpers.add(this.id, " sign() invalid base64 secret")) ;
            }
            Object signature = this.hmac(this.encode(what), secret, sha256(), "base64");
            final Object finalNonce = nonce;
            headers = new java.util.HashMap<String, Object>() {{
                put( "CB-ACCESS-KEY", CoinbaseexchangeCore.this.apiKey );
                put( "CB-ACCESS-SIGN", signature );
                put( "CB-ACCESS-TIMESTAMP", finalNonce );
                put( "CB-ACCESS-PASSPHRASE", CoinbaseexchangeCore.this.password );
                put( "Content-Type", "application/json" );
            }};
        }
        final Object finalMethod = method;
        final Object finalBody = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", url );
            put( "method", finalMethod );
            put( "body", finalBody );
            put( "headers", finalHeaders );
        }};
    }

    public Object handleErrors(Object code, Object reason, Object url, Object method, Object headers, Object body, Object response, Object requestHeaders, Object requestBody)
    {
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(code, 400))) || Helpers.isTrue((Helpers.isEqual(code, 404)))))
        {
            if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(body, 0), "{")))
            {
                Object message = this.safeString(response, "message");
                Object feedback = Helpers.add(Helpers.add(this.id, " "), message);
                this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), message, feedback);
                this.throwBroadlyMatchedException(Helpers.GetValue(this.exceptions, "broad"), message, feedback);
                throw new ExchangeError((String)feedback) ;
            }
            throw new ExchangeError((String)Helpers.add(Helpers.add(this.id, " "), body)) ;
        }
        return null;
    }

    public java.util.concurrent.CompletableFuture<Object> request(Object path, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object api = Helpers.getArg(optionalArgs, 0, "public");
            Object method = Helpers.getArg(optionalArgs, 1, "GET");
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            Object headers = Helpers.getArg(optionalArgs, 3, null);
            Object body = Helpers.getArg(optionalArgs, 4, null);
            Object config = Helpers.getArg(optionalArgs, 5, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.fetch2(path, api, method, parameters, headers, body, config)).join();
            if (Helpers.isTrue(!(response instanceof String)))
            {
                if (Helpers.isTrue(Helpers.inOp(response, "message")))
                {
                    throw new ExchangeError((String)Helpers.add(Helpers.add(this.id, " "), this.json(response))) ;
                }
            }
            return response;
        });

    }
